namespace TestProject.Configuration;

public class FileServiceOptions
{
    public string HomeDirectory { get; set; } = "Home";
}

using System.Collections.Generic;

namespace TestProject.Models;

public sealed record FileEntryDto(string Name, string Path, bool IsDirectory, long Size, System.DateTime LastModified);

public sealed record BrowseResultDto(string Path, string? Parent, IReadOnlyList<FileEntryDto> Entries, int FolderCount, int FileCount, long TotalSize);

public sealed record SearchResultDto(string Query, string Path, IReadOnlyList<FileEntryDto> Results);

public sealed record MoveRequest(string SourcePath, string DestinationPath);

public sealed record CopyRequest(string SourcePath, string DestinationPath);

using Microsoft.AspNetCore.Http;
using TestProject.Models;

namespace TestProject.Services;

/// <summary>
/// Provides path-safe file system operations confined to a configurable
/// home directory. All relative paths are validated so they cannot escape
/// the sandboxed root before any disk access occurs.
/// </summary>
public interface IFileService
{
    /// <summary>
    /// Lists the immediate children of the directory at <paramref name="relativePath"/>,
    /// returning directories first (then files), each sorted by name.
    /// </summary>
    BrowseResultDto Browse(string relativePath);

    /// <summary>
    /// Recursively searches under <paramref name="relativePath"/> for entries
    /// whose name contains <paramref name="query"/> (case-insensitive).
    /// </summary>
    SearchResultDto Search(string query, string relativePath);

    /// <summary>
    /// Resolves a relative path to its absolute, normalized counterpart within
    /// the home root. Used by controllers to stream downloads.
    /// </summary>
    string ResolveFullPath(string relativePath);

    /// <summary>
    /// Writes the uploaded <paramref name="file"/> into the directory at
    /// <paramref name="relativeDirPath"/>, creating it if necessary.
    /// </summary>
    Task UploadAsync(string relativeDirPath, IFormFile file);

    /// <summary>
    /// Deletes the file or directory (recursively) at <paramref name="relativePath"/>.
    /// </summary>
    void Delete(string relativePath);

    /// <summary>
    /// Moves the file or directory at <paramref name="request.SourcePath"/> to
    /// <paramref name="request.DestinationPath"/>.
    /// </summary>
    void Move(MoveRequest request);

    /// <summary>
    /// Copies the file or directory at <paramref name="request.SourcePath"/> to
    /// <paramref name="request.DestinationPath"/>.
    /// </summary>
    void Copy(CopyRequest request);
}

export type View = 'browse' | 'search';

export interface Route {
  view: View;
  path: string;
  query: string;
}

const DEFAULT_ROUTE: Route = { view: 'browse', path: '', query: '' };

/**
 * Parse a full hash (including leading '#') into a Route.
 *
 * Browse format:  #/browse  or  #/browse/<segments>
 * Search format:  #/search?q=<query>&path=<path>
 * Anything else returns the default browse route.
 */
export function parseHash(hash: string): Route {
  if (hash.startsWith('#/browse')) {
    const afterPrefix = hash.slice('#/browse'.length); // everything after "#/browse"
    // Remove the leading '/' if present, then URL-decode what remains
    const path = afterPrefix.startsWith('/')
      ? decodeURIComponent(afterPrefix.slice(1))
      : decodeURIComponent(afterPrefix);
    return { view: 'browse', path, query: '' };
  }

  if (hash.startsWith('#/search')) {
    const queryString = hash.slice('#/search'.length);
    const params = new URLSearchParams(queryString);
    const query = params.get('q') ?? '';
    const path = params.get('path') ?? '';
    return { view: 'search', query, path };
  }

  return DEFAULT_ROUTE;
}

/**
 * Serialize a browse path into a browse hash.
 * Each segment is independently percent-encoded.
 */
export function toBrowseHash(path: string): string {
  if (path === '') {
    return '#/browse';
  }
  const segments = path.split('/');
  const encoded = segments.map((s) => encodeURIComponent(s)).join('/');
  return '#/browse/' + encoded;
}

/**
 * Serialize query and path values into a search hash.
 * Both values are percent-encoded.
 */
export function toSearchHash(query: string, path: string): string {
  return `#/search?q=${encodeURIComponent(query)}&path=${encodeURIComponent(path)}`;
}

/**
 * Read the current route from window.location.hash.
 */
export function getCurrentRoute(): Route {
  return parseHash(window.location.hash);
}

/**
 * Subscribe to hash-change events.
 * Returns an unsubscribe function.
 */
export function subscribe(callback: () => void): () => void {
  window.addEventListener('hashchange', callback);
  return () => {
    window.removeEventListener('hashchange', callback);
  };
}

/**
 * Navigate to a given hash (sets window.location.hash).
 */
export function navigate(hash: string): void {
  window.location.hash = hash;
}

/**
 * SPA entry — wires `api`, `router`, and the DOM into a file-browser UI
 * rendered inside a native `<dialog>` widget.
 *
 * This module is the thin entry point: it builds the DOM imperatively, wires
 * toolbar/dialog events, binds the resulting element refs into the render
 * orchestrator (which owns the route dispatch and render lifecycle), and kicks
 * off the initial render. The rendering logic itself lives in the focused
 * modules under `./app/`:
 *
 *   - `./app/context.js`             — shared API client, DOM refs, render hook
 *   - `./app/dom-builders.js`        — table/breadcrumb/row/action-button builders
 *   - `./app/render-browse.js`       — browse-result rendering
 *   - `./app/render-search.js`       — search-result rendering
 *   - `./app/toolbar-handlers.js`    — search + upload handlers
 *   - `./app/render-orchestrator.js` — route dispatch + render lifecycle
 *
 * Structure (built imperatively via `document.createElement`):
 *
 *   .file-browser-host   — primary chromeless surface; hosts the widget while
 *                          the dialog is closed (embedded view)
 *   <button class="trigger">Browse Files</button>
 *   <dialog class="browser-dialog">  — frame + titlebar (dialog-only chrome)
 *     .dialog-header     — title <span> + Close icon <button>
 *     .dialog-body        — empty slot; the shared widget moves here on open
 *
 *   The shared .file-browser widget (toolbar + .results + .status) is MOVED
 *   between the embedded host and the dialog body as the dialog opens/closes.
 *   It carries no border/background/title of its own — only the dialog adds
 *   the frame + titlebar, so the embedded view is chromeless.
 *
 *   .file-browser:
 *     toolbar   — .breadcrumb + search <input> + <button> + <label> upload
 *     .results  — file/folder <table>
 *     <footer class="status"> — summary line
 *
 * All user-controlled strings (file/folder names, paths) are inserted via
 * `textContent` / element creation — never via `innerHTML` — to prevent HTML
 * injection.
 *
 * `renderBrowse` and `renderSearch` are re-exported so `src/app.test.ts`'s
 * existing `import { startApp, renderBrowse, renderSearch } from './app'`
 * continues to resolve without modification.
 */
import { doSearch, handleUpload } from './app/toolbar-handlers.js';
import { init } from './app/render-orchestrator.js';
import type { DomRefs } from './app/context.js';

export { renderBrowse } from './app/render-browse.js';
export { renderSearch } from './app/render-search.js';

/* =========================================================================
 * startApp — build the DOM, wire events, bind refs, kick off rendering
 * ========================================================================= */

export function startApp(root: HTMLElement): void {
  root.innerHTML = '';

  /* --- File-browser widget (chromeless; shared by the embedded view and the
     dialog). It owns the toolbar, results, and status. The frame and titlebar
     belong to whichever host renders it — never to the widget itself — so when
     it is embedded directly in the page it carries no border/background/title. --- */
  const widget = document.createElement('div');
  widget.className = 'file-browser';

  // Toolbar: breadcrumb, search, upload
  const toolbar = document.createElement('div');
  toolbar.className = 'toolbar';
  const breadcrumbEl = document.createElement('div');
  breadcrumbEl.className = 'breadcrumb';
  const searchInput = document.createElement('input');
  searchInput.type = 'text';
  searchInput.placeholder = 'Search...';
  const searchBtn = document.createElement('button');
  searchBtn.className = 'btn';
  searchBtn.type = 'button';
  searchBtn.textContent = 'Search';
  const uploadLabel = document.createElement('label');
  uploadLabel.className = 'btn';
  uploadLabel.textContent = 'Upload';
  const uploadInput = document.createElement('input');
  uploadInput.type = 'file';
  uploadInput.hidden = true;
  uploadInput.multiple = true;
  uploadLabel.append(uploadInput);
  toolbar.append(breadcrumbEl, searchInput, searchBtn, uploadLabel);

  // Results container + status footer
  const resultsEl = document.createElement('div');
  resultsEl.className = 'results';
  const statusEl = document.createElement('footer');
  statusEl.className = 'status';

  widget.append(toolbar, resultsEl, statusEl);

  /* --- Embedded host: the primary, chromeless surface. The widget lives here
     while the dialog is closed. --- */
  const embeddedHost = document.createElement('div');
  embeddedHost.className = 'file-browser-host';
  embeddedHost.append(widget);

  /* --- Trigger button --- */
  const trigger = document.createElement('button');
  trigger.className = 'trigger';
  trigger.textContent = 'Browse Files';

  /* --- Native <dialog>: supplies the frame (border/background) and titlebar
     (title + close). Its body is an empty slot the shared widget drops into
     when opened. --- */
  const dialog = document.createElement('dialog');
  dialog.className = 'browser-dialog';

  // Titlebar: centered title + Close (icon) button
  const header = document.createElement('div');
  header.className = 'dialog-header';
  const titleSpan = document.createElement('span');
  titleSpan.className = 'title';
  titleSpan.textContent = 'File Browser';
  const closeBtn = document.createElement('button');
  closeBtn.className = 'close-btn';
  closeBtn.type = 'button';
  // Icon button has no visible text, so expose an accessible name.
  closeBtn.setAttribute('aria-label', 'Close');
  const closeIcon = document.createElement('i');
  closeIcon.className = 'bi bi-x-lg';
  closeBtn.append(closeIcon);
  header.append(titleSpan, closeBtn);

  // Dialog body slot: the widget is moved here on open, back to the host on close.
  const dialogBody = document.createElement('div');
  dialogBody.className = 'dialog-body';

  dialog.append(header, dialogBody);
  root.append(embeddedHost, trigger, dialog);

  /* --- Event wiring --- */
  // Opening the dialog MOVES the shared widget into the dialog body (reusing
  // the same nodes, so the context refs and any in-flight render stay valid),
  // then shows it. Closing — via the close button, ESC, etc. — fires the
  // dialog's `close` event, which moves the widget back to the embedded host.
  trigger.addEventListener('click', () => {
    dialogBody.append(widget);
    dialog.showModal();
  });
  dialog.addEventListener('close', () => {
    embeddedHost.append(widget);
  });
  closeBtn.addEventListener('click', () => dialog.close());

  searchBtn.addEventListener('click', doSearch);
  searchInput.addEventListener('keydown', (event: KeyboardEvent) => {
    if (event.key === 'Enter') {
      doSearch();
    }
  });

  uploadInput.addEventListener('change', handleUpload);

  /* --- Bind refs into the orchestrator + context, subscribe, and kick off
     the initial render. --- */
  const refs: DomRefs = {
    results: resultsEl,
    status: statusEl,
    breadcrumb: breadcrumbEl,
    searchInput,
    uploadInput,
  };
  init(refs);
}

/* =========================================================================
 * Bootstrap
 *
 * Guarded so the module is importable in tests (which have no #app element)
 * without side effects. Only mounts when a real #app container exists.
 * ========================================================================= */

const appRoot = document.getElementById('app');
if (appRoot) {
  startApp(appRoot);
}

export interface FileEntry {
  name: string;
  path: string;
  isDirectory: boolean;
  size: number;
  lastModified: string;
}

export interface BrowseResult {
  path: string;
  parent: string | null;
  entries: FileEntry[];
  folderCount: number;
  fileCount: number;
  totalSize: number;
}

export interface SearchResult {
  query: string;
  path: string;
  results: FileEntry[];
}

export class ApiClient {
  constructor(private readonly baseUrl: string = '/api/files') {}

  async browse(path: string): Promise<BrowseResult> {
    return this.request<BrowseResult>(
      `${this.baseUrl}/browse?path=${encodeURIComponent(path)}`,
      { method: 'GET' }
    );
  }

  async search(query: string, path: string): Promise<SearchResult> {
    return this.request<SearchResult>(
      `${this.baseUrl}/search?query=${encodeURIComponent(query)}&path=${encodeURIComponent(path)}`,
      { method: 'GET' }
    );
  }

  async upload(path: string, file: File): Promise<{ path: string }> {
    const formData = new FormData();
    formData.append('file', file);
    return this.request<{ path: string }>(
      `${this.baseUrl}/upload?path=${encodeURIComponent(path)}`,
      { method: 'POST', body: formData }
    );
  }

  async delete(path: string): Promise<void> {
    await this.request<unknown>(
      `${this.baseUrl}/delete?path=${encodeURIComponent(path)}`,
      { method: 'DELETE' }
    );
  }

  async move(source: string, destination: string): Promise<void> {
    await this.request<unknown>(
      `${this.baseUrl}/move`,
      {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ sourcePath: source, destinationPath: destination }),
      }
    );
  }

  async copy(source: string, destination: string): Promise<void> {
    await this.request<unknown>(
      `${this.baseUrl}/copy`,
      {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ sourcePath: source, destinationPath: destination }),
      }
    );
  }

  downloadUrl(path: string): string {
    return `${this.baseUrl}/download?path=${encodeURIComponent(path)}`;
  }

  private async request<T>(url: string, init?: RequestInit): Promise<T> {
    const res = await fetch(url, init);
    if (!res.ok) {
      throw new Error(res.status + ': ' + await res.text());
    }
    return await res.json() as T;
  }
}

// @vitest-environment node
/**
 * Static-asset tests for `wwwroot/index.html` — the host page that boots the
 * SPA (`<div id="app">` + `<script type="module" src="dist/app.js">`).
 *
 * Pinned to the `node` environment because these tests only inspect the HTML
 * source: they read the file from disk and assert on its markup. They need no
 * DOM, and pinning here keeps them fast and side-effect-free. (Parsing the page
 * with happy-dom's `DOMParser` would instead try to fetch/evaluate the page's
 * `<script src="dist/app.js">` and emit unhandled rejections, so the assertions
 * below parse the raw string deterministically instead.)
 *
 * The headline contract under test is the UI/UX accessibility requirement that
 * users who arrive with JavaScript disabled/blocked see an explanatory
 * `<noscript>` message rather than a blank page, while every pre-existing
 * bootstrap element (charset, viewport, title, stylesheet, mount point, module
 * script) is left intact.
 */
import { describe, it, expect } from 'vitest';
import { readFileSync } from 'node:fs';
import { resolve, dirname } from 'node:path';
import { fileURLToPath } from 'node:url';

const __dirname = dirname(fileURLToPath(import.meta.url));
const HTML_PATH = resolve(__dirname, '../wwwroot/index.html');
const HTML = readFileSync(HTML_PATH, 'utf8');

/* ===========================================================================
 * Helpers
 * ========================================================================= */

/**
 * Extract the full `<noscript>...</noscript>` block. Non-greedy so it captures
 * only the first (and, per the "exactly one" assertion, only) noscript element.
 */
const NOSCRIPT_RE = /<noscript\b[^>]*>([\s\S]*?)<\/noscript>/i;
const noscriptMatch = HTML.match(NOSCRIPT_RE);
const noscriptBlock = noscriptMatch?.[0] ?? '';
const noscriptInner = noscriptMatch?.[1] ?? '';

/**
 * Pull an attribute's value out of a markup fragment, honoring whichever quote
 * character (`"` or `'`) delimits it. This matters here because the fallback's
 * inline `style="..."` contains single-quoted font names (e.g. 'Segoe UI')
 * inside a double-quoted attribute, so a naive `[^"']*` capture would stop at
 * the first single quote.
 */
function getAttribute(markup: string, name: string): string | null {
  const re = new RegExp(`${name}\\s*=\\s*(?:"([^"]*)"|'([^']*)')`, 'i');
  const m = markup.match(re);
  return m ? (m[1] ?? m[2] ?? '') : null;
}

/**
 * Relative luminance of a CSS color literal, per the sRGB / WCAG definition.
 * Used to assert the fallback text is *light enough to read* on the dark
 * `#1e1e1e` body background defined in `dist/app.css`, rather than merely
 * "some color". Accepts `#rgb`, `#rrggbb`, and `rgb()/rgba()` forms plus a
 * small allow-list of light named colors.
 */
function isLightColor(value: string): boolean {
  const v = value.trim().toLowerCase();
  let r: number;
  let g: number;
  let b: number;

  const hex = v.match(/^#([0-9a-f]{3}|[0-9a-f]{6})$/);
  if (hex) {
    let h = hex[1];
    if (h.length === 3) {
      h = h
        .split('')
        .map((c) => c + c)
        .join('');
    }
    r = parseInt(h.slice(0, 2), 16);
    g = parseInt(h.slice(2, 4), 16);
    b = parseInt(h.slice(4, 6), 16);
  } else if (v.startsWith('rgb')) {
    const nums = v.match(/\d+(\.\d+)?/g);
    if (!nums || nums.length < 3) return false;
    [r, g, b] = nums.map(Number);
  } else if (
    ['white', 'whitesmoke', 'aliceblue', 'azure', 'ivory', 'snow', 'seashell', 'floralwhite', 'mintcream'].includes(v)
  ) {
    return true;
  } else {
    // Unknown format: cannot prove it is light, so fail closed.
    return false;
  }

  const toLinear = (c: number) => {
    const s = c / 255;
    return s <= 0.03928 ? s / 12.92 : ((s + 0.055) / 1.055) ** 2.4;
  };
  const L = 0.2126 * toLinear(r) + 0.7152 * toLinear(g) + 0.0722 * toLinear(b);
  // WCAG's light/dark crossover (~0.179). #1e1e1e → ~0.013 (dark),
  // #e6e6e6 (the theme text color) → ~0.79 (light).
  return L > 0.179;
}

/* ===========================================================================
 * Document skeleton + preserved bootstrap markup
 * ========================================================================= */
describe('wwwroot/index.html — document skeleton', () => {
  it('is an HTML5 document', () => {
    expect(HTML).toMatch(/^<!DOCTYPE html>/i);
    expect(HTML).toMatch(/<html\b/i);
  });

  it('has <head> and <body> sections', () => {
    expect(HTML).toMatch(/<head\b/i);
    expect(HTML).toMatch(/<\/head>/i);
    expect(HTML).toMatch(/<body\b/i);
    expect(HTML).toMatch(/<\/body>/i);
  });
});

describe('wwwroot/index.html — preserved bootstrap markup', () => {
  it('declares a UTF-8 charset', () => {
    expect(HTML).toMatch(/<meta\s+charset=["']?utf-8["']?/i);
  });

  it('keeps the responsive viewport meta', () => {
    expect(HTML).toMatch(/<meta\s+name=["']viewport["']/i);
    expect(HTML).toMatch(/width=device-width/i);
    expect(HTML).toMatch(/initial-scale=1/i);
  });

  it('keeps the "File Browser" title', () => {
    expect(HTML).toMatch(/<title>\s*File Browser\s*<\/title>/i);
  });

  it('still links the compiled stylesheet dist/app.css', () => {
    expect(HTML).toMatch(/<link[^>]+href=["']dist\/app\.css["']/i);
  });

  it('still mounts the SPA into an empty #app container', () => {
    expect(HTML).toMatch(/<div\s+id=["']app["']>\s*<\/div>/i);
  });

  it('still loads the app as an ES module script dist/app.js', () => {
    expect(HTML).toMatch(/<script[^>]+type=["']module["'][^>]+src=["']dist\/app\.js["']/i);
  });
});

/* ===========================================================================
 * <noscript> fallback — the accessibility fix under test
 * ========================================================================= */
describe('wwwroot/index.html — <noscript> fallback', () => {
  it('contains exactly one <noscript> element', () => {
    const openingTags = HTML.match(/<noscript\b/gi) ?? [];
    expect(openingTags.length).toBe(1);
    expect(noscriptBlock, 'a <noscript>...</noscript> block must exist').toBeTruthy();
  });

  it('is located inside <body> (not in <head>)', () => {
    const bodyOpen = HTML.search(/<body\b/i);
    const bodyClose = HTML.search(/<\/body>/i);
    const nsStart = HTML.search(/<noscript\b/i);
    const nsEnd = nsStart >= 0 ? nsStart + noscriptBlock.length : -1;

    expect(bodyOpen, '<body> must open before the noscript').toBeGreaterThanOrEqual(0);
    expect(bodyClose, '</body> must exist').toBeGreaterThan(bodyOpen);
    expect(nsStart, 'noscript must start after <body> opens').toBeGreaterThan(bodyOpen);
    expect(nsEnd, 'noscript must end before </body>').toBeLessThan(bodyClose);
  });

  it('is placed after the #app mount point', () => {
    // The fix places the fallback immediately after `<div id="app"></div>`;
    // it must not precede the mount container.
    const appIdx = HTML.search(/<div\s+id=["']app["']/i);
    const nsIdx = HTML.search(/<noscript\b/i);
    expect(appIdx).toBeGreaterThanOrEqual(0);
    expect(nsIdx).toBeGreaterThan(appIdx);
  });

  it('provides a non-empty, human-readable message', () => {
    const text = noscriptInner
      .replace(/<[^>]+>/g, ' ')
      .replace(/\s+/g, ' ')
      .trim();
    expect(text.length).toBeGreaterThan(20);
  });

  it('tells the user the app requires JavaScript', () => {
    expect(noscriptInner.toLowerCase()).toContain('javascript');
  });

  it('is actionable — instructs the user to enable JavaScript', () => {
    expect(noscriptInner.toLowerCase()).toContain('enable');
  });

  it('uses only plain text — no interactive controls or scripts inside <noscript>', () => {
    // A fallback shown when scripting is off cannot rely on buttons, links,
    // forms, or scripts. Allow text + simple structural tags only.
    expect(/<(button|a|input|form|select|textarea|script|iframe|object|embed)\b/i.test(noscriptInner)).toBe(false);
  });

  it('styles the message so it is visible against the dark theme background', () => {
    // dist/app.css paints the body background #1e1e1e (near-black). If the
    // stylesheet also fails to load, the fallback must still be legible, so the
    // message needs an inline light foreground color.
    const style = getAttribute(noscriptInner, 'style');
    expect(style, 'the message element must carry an inline style attribute').not.toBeNull();

    // The foreground `color` declaration (guarded so it does not match
    // `background-color` / `border-color`).
    const colorMatch = style!.toLowerCase().match(/(?:^|;)\s*color\s*:\s*([^;]+)/i);
    expect(colorMatch, 'inline style must set a foreground `color`').not.toBeNull();

    const colorValue = colorMatch![1].trim();
    expect(isLightColor(colorValue), `color "${colorValue}" must be light enough to read on #1e1e1e`).toBe(true);
  });
});

/**
 * Shared services for the file-browser app modules.
 *
 * The file-browser is split across several focused modules (dom-builders,
 * render-browse, render-search, toolbar-handlers, render-orchestrator). They
 * all need access to three cross-cutting things that `startApp` establishes
 * once per mount:
 *
 *   - the {@link ApiClient} singleton (used for fetches and download URLs);
 *   - the DOM element refs the render helpers write into (results, status,
 *     breadcrumb, search input, upload input);
 *   - a "render hook" that action-button handlers and the upload handler call
 *     to trigger a fresh route dispatch (used instead of importing the
 *     orchestrator directly, which would create a module cycle: orchestrator →
 *     render-browse → dom-builders → orchestrator).
 *
 * Centralizing them here keeps the cross-module dependency graph acyclic and
 * makes the re-bind-on-remount contract explicit — replacing the bare
 * module-level `let resultsEl!: HTMLElement` variables that used to live in
 * `app.ts`. `render-orchestrator.init` re-binds the refs every mount, so the
 * render helpers always target the most recently mounted app.
 */
import { ApiClient } from '../api.js';

/** The DOM element refs established by each `startApp` mount. */
export interface DomRefs {
  results: HTMLElement;
  status: HTMLElement;
  breadcrumb: HTMLElement;
  searchInput: HTMLInputElement;
  uploadInput: HTMLInputElement;
}

/* -------------------------------------------------------------------------
 * API singleton
 *
 * Created once at module load, exactly as the original `app.ts` created
 * `const api = new ApiClient();` at its top level. The constructor performs
 * no I/O, so creating it before `fetch` is stubbed in a test is safe.
 * ---------------------------------------------------------------------- */
const api = new ApiClient();

/** The shared API client (used for fetches and download-URL construction). */
export function getApi(): ApiClient {
  return api;
}

/* -------------------------------------------------------------------------
 * DOM refs — rebound by `render-orchestrator.init` on every `startApp` mount
 * so `renderBrowse` / `renderSearch` always target the most recent mount.
 *
 * The definite-assignment assertions mirror the original `let resultsEl!:
 * HTMLElement` pattern: the refs are uninitialized only until the first
 * `init()` call, which always runs before any render helper reads them.
 * ---------------------------------------------------------------------- */
let results!: HTMLElement;
let status!: HTMLElement;
let breadcrumb!: HTMLElement;
let searchInput!: HTMLInputElement;
let uploadInput!: HTMLInputElement;

/** Bind the DOM refs for the current mount. Called from the orchestrator's `init`. */
export function setRefs(refs: DomRefs): void {
  results = refs.results;
  status = refs.status;
  breadcrumb = refs.breadcrumb;
  searchInput = refs.searchInput;
  uploadInput = refs.uploadInput;
}

export function getResults(): HTMLElement {
  return results;
}

export function getStatus(): HTMLElement {
  return status;
}

export function getBreadcrumb(): HTMLElement {
  return breadcrumb;
}

export function getSearchInput(): HTMLInputElement {
  return searchInput;
}

export function getUploadInput(): HTMLInputElement {
  return uploadInput;
}

/* -------------------------------------------------------------------------
 * Render hook
 *
 * Action-button handlers (in dom-builders) and the upload handler (in
 * toolbar-handlers) call `rerender()` to trigger a fresh route dispatch. They
 * cannot import `render` from render-orchestrator.ts directly without creating
 * the cycle noted above, so the orchestrator registers its `render` function
 * here during `init` and the callers invoke it indirectly through `rerender`.
 * ---------------------------------------------------------------------- */
let renderHook: () => Promise<void> = async () => {};

/** Register the route-dispatching render function. */
export function setRenderHook(fn: () => Promise<void>): void {
  renderHook = fn;
}

/** Trigger a fresh render via the registered hook. No-op until `setRenderHook` is called. */
export function rerender(): Promise<void> {
  return renderHook();
}

/**
 * Route dispatcher and rendering-lifecycle owner.
 *
 * `render` reads the current route, fetches the matching result from the API,
 * and delegates to `renderBrowse` / `renderSearch`. It guards against render
 * races (a slower, superseded fetch cannot clobber fresher results) via a
 * monotonic token checked after each `await`.
 *
 * `init` is called once per `startApp` mount: it binds the freshly-built DOM
 * refs into the shared context, registers `render` as the re-render hook (so
 * action buttons and uploads can trigger it without a circular import), tears
 * down any previous mount's hashchange listener, subscribes a new one, and
 * kicks off the initial render.
 */
import { getCurrentRoute, subscribe } from '../router.js';
import { normalizeRelativePath } from '../format.js';
import { getApi, getResults, setRefs, setRenderHook, type DomRefs } from './context.js';
import { renderBrowse } from './render-browse.js';
import { renderSearch } from './render-search.js';

/* -------------------------------------------------------------------------
 * Rendering-lifecycle state
 *
 * `unsubscribe` holds the teardown for the CURRENT mount's hashchange listener.
 * `init` clears any previous listener before subscribing a new one, so a
 * re-mount never leaves the old listener on `window` (memory leak fix).
 *
 * `renderToken` is a monotonic counter incremented at the start of every
 * `render()`. Each in-flight render captures its token and, after each `await`,
 * bails out if a newer render has started — preventing a slower, superseded
 * fetch from clobbering the freshest results (render-race fix).
 * ---------------------------------------------------------------------- */
let unsubscribe: (() => void) | null = null;
let renderToken = 0;

/**
 * Bind the freshly-built DOM refs into the shared context, register `render`
 * as the re-render hook, tear down any previous mount's hashchange listener,
 * subscribe a new one, and kick off the initial render.
 */
export function init(refs: DomRefs): void {
  setRefs(refs);
  setRenderHook(render);
  // Tear down the previous mount's listener first (if any) so re-mounts never
  // accumulate hashchange listeners on `window`.
  if (unsubscribe !== null) {
    unsubscribe();
    unsubscribe = null;
  }
  unsubscribe = subscribe(render);
  render();
}

/**
 * Route dispatcher.
 *
 * Clears the results container synchronously (so a pending/failed fetch never
 * leaves a stale table behind) but does NOT clear the breadcrumb or status
 * here. Clearing those synchronously would remove in-page navigation targets
 * in the middle of a click handler: `navigate()` dispatches `hashchange`
 * synchronously in happy-dom, which would re-enter `render` and wipe the
 * breadcrumb before the click's caller can read the next segment. The
 * breadcrumb/status are instead refreshed by `renderBrowse`/`renderSearch`
 * once data arrives.
 */
export async function render(): Promise<void> {
  // Claim this render slot. A newer render increments `renderToken` past
  // `myToken`; after each `await` we bail out if superseded so a slower fetch
  // can never overwrite the freshest results, breadcrumb, or status.
  const myToken = ++renderToken;
  const route = getCurrentRoute();
  const resultsEl = getResults();
  resultsEl.innerHTML = '';
  try {
    if (route.view === 'browse') {
      const result = await getApi().browse(normalizeRelativePath(route.path));
      if (myToken !== renderToken) return;
      renderBrowse(result);
    } else {
      const result = await getApi().search(route.query, normalizeRelativePath(route.path));
      if (myToken !== renderToken) return;
      renderSearch(result);
    }
  } catch (err) {
    // A superseded render must not even commit its error.
