export function makeNavLink(text: string, hash: string): HTMLAnchorElement {
  const link = document.createElement('a');
  link.setAttribute('href', hash);
  link.textContent = text;
  link.addEventListener('click', (event) => {
    event.preventDefault();
    navigate(hash);
  });
  return link;
}

/** The ".." parent row: a Name cell whose link navigates to the parent path. */
export function makeParentRow(parent: string): HTMLTableRowElement {
  const row = document.createElement('tr');
  const nameCell = document.createElement('td');
  nameCell.append(makeNavLink('..', toBrowseHash(parent)));
  const sizeCell = document.createElement('td');
  const modifiedCell = document.createElement('td');
  const actionsCell = document.createElement('td');
  row.append(nameCell, sizeCell, modifiedCell, actionsCell);
  return row;
}

/** One data row in the browse table (a file or folder entry). */
export function makeBrowseRow(entry: FileEntry): HTMLTableRowElement {
  const row = document.createElement('tr');

  // Name — directory names are navigation links; file names are plain text.
  const nameCell = document.createElement('td');
  if (entry.isDirectory) {
    nameCell.append(makeNavLink(entry.name, toBrowseHash(entry.path)));
  } else {
    nameCell.textContent = entry.name;
  }

  // Size — em-dash for folders, formatted bytes for files.
  const sizeCell = document.createElement('td');
  sizeCell.textContent = entry.isDirectory ? '—' : formatBytes(entry.size);

  // Modified
  const modifiedCell = document.createElement('td');
  modifiedCell.textContent = formatDate(entry.lastModified);

  // Actions
  const actionsCell = document.createElement('td');
  if (!entry.isDirectory) {
    const download = document.createElement('a');
    download.className = 'btn';
    download.setAttribute('href', getApi().downloadUrl(entry.path));
    download.setAttribute('download', entry.name);
    download.textContent = 'Download';
    actionsCell.append(download);
  }
  actionsCell.append(makeActionButton('Delete', async () => {
    if (!window.confirm('Delete "' + entry.name + '"?')) {
      return;
    }
    await getApi().delete(entry.path);
    rerender();
  }));
  actionsCell.append(makeActionButton('Move', async () => {
    const dest = window.prompt('Move to relative destination path:', entry.path);
    if (dest === null) {
      return;
    }
    await getApi().move(entry.path, normalizeRelativePath(dest));
    rerender();
  }));
  actionsCell.append(makeActionButton('Copy', async () => {
    const dest = window.prompt('Copy to relative destination path:', entry.path);
    if (dest === null) {
      return;
    }
    await getApi().copy(entry.path, normalizeRelativePath(dest));
    rerender();
  }));

  row.append(nameCell, sizeCell, modifiedCell, actionsCell);
  return row;
}

/**
 * Build a `<button class="btn">` with the given label and click handler.
 *
 * The handler is wrapped so that any synchronous throw or promise rejection
 * surfaces the error via the status footer — consistent with how `render()`
 * already displays fetch errors. On normal resolution no error message is
 * shown.
 */
export function makeActionButton(label: string, handler: () => void): HTMLButtonElement {
  const btn = document.createElement('button');
  btn.className = 'btn';
  btn.type = 'button';
  btn.textContent = label;
  btn.addEventListener('click', () => {
    try {
      Promise.resolve(handler()).catch((err: unknown) => {
        getStatus().textContent = 'Error: ' + (err instanceof Error ? err.message : String(err));
      });
    } catch (err) {
      getStatus().textContent = 'Error: ' + (err instanceof Error ? err.message : String(err));
    }
  });
  return btn;
}

/** One data row in the search-results table. */
export function makeSearchRow(entry: FileEntry): HTMLTableRowElement {
  const row = document.createElement('tr');

  // Name — directories browse into; files open their download URL.
  const nameCell = document.createElement('td');
  if (entry.isDirectory) {
    nameCell.append(makeNavLink(entry.name, toBrowseHash(entry.path)));
  } else {
    const link = document.createElement('a');
    link.setAttribute('href', getApi().downloadUrl(entry.path));
    link.textContent = entry.name;
    nameCell.append(link);
  }

  // Path
  const pathCell = document.createElement('td');
  pathCell.textContent = entry.path;

  // Size
  const sizeCell = document.createElement('td');
  sizeCell.textContent = formatBytes(entry.size);

  // Modified
  const modifiedCell = document.createElement('td');
  modifiedCell.textContent = formatDate(entry.lastModified);

  row.append(nameCell, pathCell, sizeCell, modifiedCell);
  return row;
}

/**
 * Render a {@link BrowseResult} into the shared results/breadcrumb/status
 * elements: a four-column table (Name | Size | Modified | Actions) with an
 * optional leading ".." parent row.
 *
 * Operates against the DOM context established by `startApp` (via
 * `render-orchestrator.init`), so it always targets the most recently mounted
 * app.
 */
import type { BrowseResult } from '../api.js';
import { formatBytes } from '../format.js';
import { buildTable, makeBrowseRow, makeParentRow, renderBreadcrumb } from './dom-builders.js';
import { getResults, getStatus } from './context.js';

export function renderBrowse(result: BrowseResult): void {
  // Breadcrumb (clickable cumulative-path segments)
  renderBreadcrumb(result.path);

  // Status footer: "N folders, M files, total S"
  getStatus().textContent =
    result.folderCount + ' folders, ' +
    result.fileCount + ' files, total ' +
    formatBytes(result.totalSize);

  // Results table
  const resultsEl = getResults();
  resultsEl.innerHTML = '';
  const table = buildTable(['Name', 'Size', 'Modified', 'Actions']);
  const tbody = table.querySelector('tbody')!;

  if (result.parent !== null) {
    tbody.append(makeParentRow(result.parent));
  }
  for (const entry of result.entries) {
    tbody.append(makeBrowseRow(entry));
  }

  resultsEl.append(table);
}

/**
 * Render a {@link SearchResult} into the shared results/breadcrumb/status
 * elements: a four-column table (Name | Path | Size | Modified).
 *
 * Operates against the DOM context established by `startApp` (via
 * `render-orchestrator.init`), so it always targets the most recently mounted
 * app.
 */
import type { SearchResult } from '../api.js';
import { buildTable, makeSearchRow, renderBreadcrumb } from './dom-builders.js';
import { getResults, getStatus } from './context.js';

export function renderSearch(result: SearchResult): void {
  // Breadcrumb reflects the search-scope path.
  renderBreadcrumb(result.path);

  // Status footer: 'R results for "q"'
  getStatus().textContent = result.results.length + ' results for "' + result.query + '"';

  // Results table
  const resultsEl = getResults();
  resultsEl.innerHTML = '';
  const table = buildTable(['Name', 'Path', 'Size', 'Modified']);
  const tbody = table.querySelector('tbody')!;

  for (const entry of result.results) {
    tbody.append(makeSearchRow(entry));
  }

  resultsEl.append(table);
}

/**
 * Toolbar event handlers: search submission and file upload.
 *
 * Both operate against the shared DOM/API context (search input value, upload
 * input file list, current route) and trigger a re-render via the context's
 * render hook.
 */
import { getCurrentRoute, navigate, toBrowseHash, toSearchHash } from '../router.js';
import { normalizeRelativePath } from '../format.js';
import { getApi, getSearchInput, getStatus, getUploadInput, rerender } from './context.js';

/**
 * Navigate to a search hash for the current input value and browse path.
 *
 * An empty (or whitespace-only) query clears the search instead: it navigates
 * to the browse route for the current path so the server never receives an
 * empty `query`, which it rejects with 400.
 */
export function doSearch(): void {
  const path = normalizeRelativePath(getCurrentRoute().path);
  const query = getSearchInput().value.trim();
  if (query === '') {
    navigate(toBrowseHash(path));
    return;
  }
  navigate(toSearchHash(query, path));
}

/**
 * Upload every selected file to the current path, handle per-file errors, then
 * clear the input, re-render the listing, and surface any failures in the
 * status footer.
 */
export async function handleUpload(): Promise<void> {
  const uploadInput = getUploadInput();
  const list = uploadInput.files;
  const files = list ? Array.from(list) : [];
  if (files.length === 0) {
    return;
  }
  const path = normalizeRelativePath(getCurrentRoute().path);
  const failed: string[] = [];
  for (const file of files) {
    try {
      await getApi().upload(path, file);
    } catch {
      failed.push(file.name);
    }
  }
  // Clear the input so selecting the same file again re-fires `change`.
  uploadInput.value = '';
  // Re-render the listing first so normal browse/search status is set.
  await rerender();
  // Surface failures after the normal render, so the message is not overwritten.
  if (failed.length > 0) {
    const succeeded = files.length - failed.length;
    getStatus().textContent = `Uploaded ${succeeded} file(s); failed: ${failed.join(', ')}`;
  }
}

/**
 * Pure formatting helpers for the file browser UI.
 *
 * Every function in this module is side-effect free (no DOM access, no network)
 * so each can be unit-tested in isolation. The module exports ONLY the six
 * functions declared here.
 */

/** Binary (1024-based) byte-unit suffixes, from bytes up to terabytes. */
const BYTE_UNITS = ["B", "KB", "MB", "GB", "TB"] as const;

/**
 * Format a byte count as a human-readable string using binary (1024-based)
 * units.
 *
 * - Values below 1024 render as an integer byte count, e.g. `0 B`, `1023 B`.
 * - Values of 1024 and above render with exactly one decimal place, keeping a
 *   trailing `.0`, e.g. `1.0 KB`, `1.5 KB`, `1.0 MB`.
 *
 * The unit caps at `TB`; values beyond 1024 TB remain expressed in terabytes.
 */
export function formatBytes(bytes: number): string {
    const units = BYTE_UNITS;
    let value = bytes;
    let unitIndex = 0;

    while (value >= 1024 && unitIndex < units.length - 1) {
        value /= 1024;
        unitIndex++;
    }

    if (unitIndex === 0) {
        // Below the KB boundary: render as an integer byte count.
        return `${Math.round(value)} ${units[unitIndex]}`;
    }

    // KB and above: one decimal place (trailing .0 preserved per spec).
    return `${value.toFixed(1)} ${units[unitIndex]}`;
}

/**
 * Normalize a relative path into a clean, slash-joined form.
 *
 * - backslashes (`\`) become forward slashes
 * - leading/trailing slashes are trimmed
 * - runs of repeated slashes collapse to one
 * - `.` and `..` segments are dropped (filtered out, NOT resolved against the
 *   parent — this also neutralizes path-traversal segments)
 * - empty/root input collapses to `""`
 */
export function normalizeRelativePath(path: string): string {
    return path
        .replace(/\\/g, "/")
        .split("/")
        .filter((segment) => segment !== "" && segment !== "." && segment !== "..")
        .join("/");
}

/**
 * Join two path fragments with a single separating slash, then normalize the
 * result (see {@link normalizeRelativePath}).
 */
export function joinPath(base: string, name: string): string {
    return normalizeRelativePath(`${base}/${name}`);
}

/**
 * Return the normalized parent relative path, or `""` when the path is already
 * at root (empty or a single segment after normalization).
 */
export function parentPath(path: string): string {
    const normalized = normalizeRelativePath(path);
    const lastSlash = normalized.lastIndexOf("/");
    return lastSlash === -1 ? "" : normalized.slice(0, lastSlash);
}

/**
 * Return the last segment of a normalized path. Returns `""` for an empty
 * path.
 */
export function basename(path: string): string {
    const normalized = normalizeRelativePath(path);
    const lastSlash = normalized.lastIndexOf("/");
    return lastSlash === -1 ? normalized : normalized.slice(lastSlash + 1);
}

/** Left-pad a number to two digits with a leading zero. */
function padTwo(value: number): string {
    return String(value).padStart(2, "0");
}

/**
 * Format an ISO 8601 date string as `yyyy-MM-dd HH:mm` (local calendar time).
 *
 * Returns `""` for empty or unparseable input instead of throwing.
 */
export function formatDate(iso: string): string {
    if (!iso) {
        return "";
    }

    const date = new Date(iso);
    if (Number.isNaN(date.getTime())) {
        return "";
    }

    const year = date.getFullYear();
    const month = padTwo(date.getMonth() + 1);
    const day = padTwo(date.getDate());
    const hours = padTwo(date.getHours());
    const minutes = padTwo(date.getMinutes());

    return `${year}-${month}-${day} ${hours}:${minutes}`;
}

